import { FontAwesomeIcon } from '@fortawesome/react-fontawesome'
import { Badge,Button,Row,Col,Form, InputGroup, Tabs, Tab } from 'react-bootstrap'
import { React, useState, useEffect} from 'react'
import ReactQuill from 'react-quill';
import 'react-quill/dist/quill.snow.css'; // import styles
import useStore from '../pages/store'

export function appendFormData(formData, data) {
    if (data instanceof Array) {
        data.forEach(item => {
            const { key, value } = item;
            if (value !== null && value !== undefined) {
                formData.append(key, value);
            }
        });
    } else if (typeof data === 'object') {
        for (const key in data) {
            const value = data[key];
            if (value !== null && value !== undefined) {
                formData.append(key, value);
            }
        }
    }
}

const quillModules = {
    toolbar: {
        container: [
            [{ header: [1, 2, 3, false] }],
            ['bold', 'italic', 'underline', 'strike'],
            [{ list: 'ordered' }, { list: 'bullet' }],
            [{ align: [] }],
            ['link', 'image'],
            ['clean'],
        ],
        handlers: {
            image: function () {
                const url = prompt('Paste image URL:');
                if (url) {
                    const quill = this.quill;
                    const range = quill.getSelection();
                    quill.insertEmbed(range?.index || 0, 'image', url);
                }
            },
        },
    },
};

export function TextEditor({fieldName}){
    const store = useStore()
    const errors = store.getValue('errors')

    return (
        <div className="mb-5">
            <ReactQuill
              value={store.getValue(fieldName) ||  ''}
              onChange={(content) => {
                store.setValue(fieldName, content);
              }}
              modules={quillModules}
              style={{ height: '400px' }}
            />

